const headers = $input.item.json.headers || {};
const auth = headers['authorization'] || headers['Authorization'] || '';
const token = auth.toLowerCase().startsWith('bearer ') ? auth.slice(7).trim() : '';
if (!token) return { json: { ok: false, status: 401, error: 'Missing session token' } };
return { json: { token } };

const rows = $input.item.json;
const row = Array.isArray(rows) ? (rows[0] || null) : (rows && (rows.id || rows.user_id) ? rows : null);
if (!row) return { json: { ok: false, status: 401, error: 'Invalid or expired session' } };
if (row.user_role !== 'admin') return { json: { ok: false, status: 403, error: 'Admin access required' } };
return { json: { ok: true } };

// Merge recent activity from 4 sources -> today counts + last 15 events.
// allOf() collects multi-row response items safely under both n8n auto-split
// and non-split behaviours.
const allOf = function (name) {
  try {
    const items = $(name).all().map(function (i) { return i.json; });
    if (items.length === 1 && Array.isArray(items[0])) return items[0];
    return items;
  } catch (e) { return []; }
};

const leads     = allOf('Recent Leads');
const bookings  = allOf('Recent Bookings');
const outreach  = allOf('Recent Outreach');
const emails    = allOf('Recent Emails');

const startOfToday = new Date(); startOfToday.setHours(0,0,0,0);
const startMs = startOfToday.getTime();

const isToday = function (iso) { if (!iso) return false; var t = new Date(iso).getTime(); return t >= startMs; };

const events = [];

leads.forEach(function (l) {
  if (!l || !l.date_created) return;
  var label = (l.company || 'Lead') + ' \u2014 ' + (l.industry || 'unknown industry') + (l.city ? ' \u2022 ' + l.city : '');
  events.push({ ts: l.date_created, kind: 'lead_created', label: label, status: l.lead_status });
});

bookings.forEach(function (b) {
  if (!b || !b.created_at) return;
  var when = b.booking_at ? new Date(b.booking_at).toISOString().slice(0,16).replace('T',' ') : 'TBD';
  events.push({ ts: b.created_at, kind: 'booking_created', label: 'Booking for ' + when + (b.channel ? ' (' + b.channel + ')' : ''), status: null });
});

outreach.forEach(function (o) {
  if (!o || !o.created_at) return;
  var ch = (o.channel || 'outreach').toLowerCase();
  events.push({ ts: o.created_at, kind: 'outreach_' + ch, label: ch.toUpperCase() + ' sent' + (o.status ? ' \u2014 ' + o.status : ''), status: o.status });
});

emails.forEach(function (e) {
  if (!e || !e.sent_at) return;
  var subj = e.subject ? (e.subject.length > 64 ? e.subject.slice(0,61) + '\u2026' : e.subject) : '(no subject)';
  events.push({ ts: e.sent_at, kind: 'email_sent', label: 'Email \u2014 ' + subj + (e.recipient ? ' to ' + e.recipient : ''), status: e.status });
});

events.sort(function (a, b) { return new Date(b.ts).getTime() - new Date(a.ts).getTime(); });
const recent = events.slice(0, 15);

const todayLeads    = leads.filter(function (l) { return isToday(l.date_created); }).length;
const todayBookings = bookings.filter(function (b) { return isToday(b.created_at); }).length;
const todayOutreach = outreach.filter(function (o) { return isToday(o.created_at); });
const todayEmails   = emails.filter(function (e) { return isToday(e.sent_at); }).length;

const byChannel = { sms: 0, whatsapp: 0, linkedin: 0, voice: 0, other: 0 };
todayOutreach.forEach(function (o) {
  var c = (o.channel || '').toLowerCase();
  if (byChannel[c] != null) byChannel[c]++; else byChannel.other++;
});

return { json: { ok: true, data: {
  today_counts: {
    new_leads:   todayLeads,
    bookings:    todayBookings,
    emails_sent: todayEmails,
    sms_sent:    byChannel.sms,
    whatsapp:    byChannel.whatsapp,
    voice_calls: byChannel.voice,
    total_touches: todayEmails + byChannel.sms + byChannel.whatsapp + byChannel.linkedin + byChannel.voice + byChannel.other
  },
  recent_activity: recent
} } };
